import logo from './logo.svg';

import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';

import NavigationBar from './NavigationBar';
import SimpleCarousel from './SimpleCarousel';
import ScrollProgressBar from './ScrollProgressBar';
import CollapsedText from './CollapsedText'; 
import { Parallax, ParallaxLayer } from '@react-spring/parallax';


function App() {
  return (
    <div className="App">
      <header>
        <NavigationBar />
      </header>

      <body>

        <Parallax pages={4}>
            <ParallaxLayer 
            offset={1} 
            speed={0.5}
            factor={2}
            style={{
              backgroundImage: 'url(${moon})',
              backgroundSize: 'cover',
            }}
            />
              <ParallaxLayer 
            offset={1} 
            speed={0.5}
            factor={2}
            style={{
              backgroundImage: 'url(${moon})',
              backgroundSize: 'cover',
            }}
            />
              <ParallaxLayer 
            offset={1} 
            speed={0.5}
            factor={2}
            style={{
              backgroundImage: 'url(${moon})',
              backgroundSize: 'cover',
            }}
            />
        </Parallax>
      
        <section id="section-0">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-1">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-2">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-3">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-4">
          <SimpleCarousel />
          <CollapsedText />
        </section>
      </body>

      <footer>
        <ScrollProgressBar />
      </footer>
    </div>
  );
}


export default App;
